# 3D image processing example# Read 3D tif image, display slices, smooth image, threshold slice by slice, and save result.import numpy as npimport matplotlib.pyplot as pltfrom skimage import io, img_as_ubytefrom skimage.filters import gaussianimport tifffile# =========================# 1. Read 3D image# =========================img_3d = io.imread("../data/3d_image.tif")# Convert image to 8-bit unsigned integerimg_3d = img_as_ubyte(img_3d)print("Image type:", type(img_3d))print("Image shape:", img_3d.shape)# =========================# 2. Show three orthogonal planes# =========================def show_plane(ax, plane, cmap="gray", title=None):    ax.imshow(plane, cmap=cmap)    ax.axis("off")    if title is not None:        ax.set_title(title)n_plane, n_row, n_col = img_3d.shapefig, (ax1, ax2, ax3) = plt.subplots(ncols=3, figsize=(15, 5))# XY plane: one normal image sliceshow_plane(    ax1,    img_3d[n_plane // 2, :, :],    title=f"Plane = {n_plane // 2}")# XZ plane: middle row through all z slicesshow_plane(    ax2,    img_3d[:, n_row // 2, :],    title=f"Row = {n_row // 2}")# YZ plane: middle column through all z slicesshow_plane(    ax3,    img_3d[:, :, n_col // 2],    title=f"Column = {n_col // 2}")plt.tight_layout()plt.show()# =========================# 3. Display many slices# =========================def display_slices(im3d, cmap="gray", step=2):    fig, axes = plt.subplots(nrows=5, ncols=6, figsize=(16, 14))    vmin = im3d.min()    vmax = im3d.max()    for ax, image in zip(axes.flatten(), im3d[::step]):        ax.imshow(image, cmap=cmap, vmin=vmin, vmax=vmax)        ax.set_xticks([])        ax.set_yticks([])    plt.tight_layout()    plt.show()display_slices(img_3d, step=2)# =========================# 4. Gaussian smoothing# =========================gaussian_smoothed = gaussian(img_3d, sigma=1)slice_index = 50fig, (ax1, ax2) = plt.subplots(ncols=2, figsize=(12, 6))ax1.imshow(img_3d[slice_index, :, :], cmap="gray")ax1.set_title("Original")ax1.axis("off")ax2.imshow(gaussian_smoothed[slice_index, :, :], cmap="gray")ax2.set_title("Smoothed")ax2.axis("off")plt.tight_layout()plt.show()# =========================# 5. Process each slice one by one# =========================binary_slices = []threshold_value = 50for z in range(img_3d.shape[0]):    # Extract one 2D slice from the 3D image    input_slice = img_3d[z, :, :]    # Threshold the slice    binary_slice = input_slice > threshold_value    # Store the processed slice    binary_slices.append(binary_slice)# Convert list of 2D slices back to a 3D numpy arrayprocessed_img = np.array(binary_slices)print("Processed image shape:", processed_img.shape)print("Processed image dtype:", processed_img.dtype)# Display processed slicesdisplay_slices(processed_img, cmap="gray", step=2)# Show one processed sliceplt.figure()plt.imshow(processed_img[100, :, :], cmap="gray")plt.title("Processed Slice")plt.axis("off")plt.show()# Save processed 3D imageio.imsave("../data/processed.tif", img_as_ubyte(processed_img))# =========================# 6. Read image using tifffile# =========================tiff_3d_img = tifffile.imread("../data/3d_image.tif")print("tifffile image shape:", tiff_3d_img.shape)# =========================# 7. Read CZI file# =========================# pip install czifileimport czifileczi_img = czifile.imread("../data/multi_channel_z_stack_time_series.czi")print("CZI image shape:", czi_img.shape)# Example shape:# scene, time, channel, z, y, x, RGB# Extract one image:# scene = 0# time = 5# channel = 0 or 1# z slice = 11# RGB = 0 because this is grayscale stored with an extra dimensionimg_ch0 = czi_img[0, 5, 0, 11, :, :, 0]img_ch1 = czi_img[0, 5, 1, 11, :, :, 0]fig, (ax1, ax2) = plt.subplots(ncols=2, figsize=(12, 6))ax1.imshow(img_ch0, cmap="cubehelix")ax1.set_title("Channel 0")ax1.axis("off")ax2.imshow(img_ch1, cmap="hot")ax2.set_title("Channel 1")ax2.axis("off")plt.tight_layout()plt.show()